sql:
SELECT AVG(data_values) AS avg_value, COUNT(data_values) AS total_entries
FROM data
WHERE project_id = 1;

SELECT project_id, project_name
FROM projects
WHERE status = 'active';

SELECT data_name, AVG(data_values) AS average_value
FROM data
GROUP BY data_name;

